const parseAmount = (value) => {
  if (value === undefined || value === null || value === '') { return 0; }
  const num = Number(value);
  return Number.isNaN(num) ? 0 : num;
};

const parseInteger = (value, fallback = 0) => {
  if (value === undefined || value === null || value === '') { return fallback; }
  const num = Number(value);
  return Number.isNaN(num) ? fallback : Math.round(num);
};

const normalizeTransaction = (tx, index) => {
  if (!tx) { return null; }

  // service_type from new response, fallback to type or services.name
  let serviceType = (
    tx.service_type ||
    tx.services?.name ||
    tx.type ||
    'unknown'
  ).toString().toLowerCase().trim();

  if (serviceType === '055f5e9a-c888-4523-9cc2-44260d5a1635') {
    serviceType = 'wallet_transfer';
  }

  const amount = parseAmount(tx.amount);

  const rawDate = tx.created_at || tx.date;
  const createdAt = rawDate ? new Date(rawDate) : null;
  const isoDate = createdAt && !Number.isNaN(createdAt.getTime()) ? createdAt.toISOString() : '';
  const dateKey = createdAt && !Number.isNaN(createdAt.getTime()) ? createdAt.toISOString().slice(0, 10) : '';
  const displayDate = createdAt && !Number.isNaN(createdAt.getTime())
    ? createdAt.toLocaleString()
    : '—';

  // Determine if this is a collection or disbursement to pick correct customer fields
  const isCollection = serviceType === 'collection' || serviceType === 'collections';

  // Customer fields — two patterns depending on service type:
  //  Collections: deductedcustomername / deductedcustomerphonenumber
  //  Disbursements/wallet: destination_name / destination_number  OR  recipient_name / recipient_phone
  const customerObj = tx.customers || null;

  let customerName;
  let customerPhone;

  if (customerObj) {
    customerName = [customerObj.first_name, customerObj.last_name].filter(Boolean).join(' ') || '—';
    customerPhone = customerObj.phone || '—';
  } else if (isCollection) {
    // Collections API returns deductedcustomer* fields
    customerName = tx.deductedcustomername || tx.customer_name || tx.customerName || '—';
    customerPhone = tx.deductedcustomerphonenumber || tx.customer_phone || tx.customerPhone || '—';
  } else {
    // Disbursements/wallet API returns destination_name / destination_number
    customerName = tx.destination_name || tx.recipient_name || tx.customer_name || tx.customerName || '—';
    customerPhone = tx.destination_number || tx.recipient_phone || tx.customer_phone || tx.customerPhone || '—';
  }

  // Reference — prefer system_reference for wallet transfers, then reference
  const reference = tx.system_reference || tx.reference || tx.customer_reference_id || `txn-${index}`;

  return {
    id: reference,
    reference,
    customerName,
    customerPhone,
    narration: tx.description || tx.narration || '—',
    collectionType: tx.collection_type || '—',
    channel: tx.channel || '—',
    reason: tx.async_response_message || tx.response_message || tx.reason || '',
    type: serviceType,
    transactionType: tx.transaction_type || null, // CREDIT / DEBIT
    balanceBefore: tx.balance_before || null,
    balanceAfter: tx.balance_after || null,
    settlementStatus: tx.settlement_status || null,
    amount,
    status: (() => {
      const rawStatus = (tx.status || 'unknown').toString().toLowerCase();
      const statusMap = {
        success: 'success', completed: 'success', succeeded: 'success',
        failed: 'failed', error: 'failed', cancelled: 'failed', rejected: 'failed',
        pending: 'pending', processing: 'pending', sent: 'pending',
      };
      return statusMap[rawStatus] || rawStatus;
    })(),
    date: isoDate,
    dateKey,
    displayDate,
    isCollection,
  };
};

const TYPE_BADGE_STYLES = {
  collection: { background: 'var(--success-bg)', color: 'var(--success)' },
  disbursement: { background: 'var(--info-bg)', color: 'var(--info)' },
  refund: { background: 'var(--warning-bg)', color: 'var(--warning)' },
  wallet_transfer: { background: 'var(--accent-bg, rgba(59, 130, 246, 0.12))', color: 'var(--accent, #3b82f6)' },
  'wallet-transfer': { background: 'var(--accent-bg, rgba(59, 130, 246, 0.12))', color: 'var(--accent, #3b82f6)' },
  utility: { background: 'var(--success-bg)', color: 'var(--success)' },
  invoice: { background: 'var(--warning-bg)', color: 'var(--warning)' },
};

const STATUS_BADGE_STYLES = {
  success: { background: 'var(--success-bg)', color: 'var(--success)' },
  pending: { background: 'var(--warning-bg)', color: 'var(--warning)' },
  failed: { background: 'var(--error-bg)', color: 'var(--error)' },
};

const getTypeBadgeStyles = (type) => {
  const normalized = type ? type.toLowerCase() : 'unknown';
  return TYPE_BADGE_STYLES[normalized] || { background: 'var(--bg-tertiary)', color: 'var(--text-primary)' };
};

const getStatusBadgeStyles = (status) => {
  const normalized = status ? status.toLowerCase() : 'unknown';
  return STATUS_BADGE_STYLES[normalized] || { background: 'var(--bg-tertiary)', color: 'var(--text-primary)' };
};

const formatLabel = (value) =>
  value
    ? value
      .toString()
      .replace(/[_-]+/g, ' ')
      .replace(/\b\w/g, (char) => char.toUpperCase())
    : '—';

const SERVICE_TYPE_ALIASES = {
  all: ['all'],
  collection: ['collection', 'collections'],
  disbursement: ['disbursement', 'disbursements', 'wallet_transfer', 'wallet-transfer', 'wallet transfer'],
  utility: ['utility', 'utilities', 'electricity', 'water', 'internet', 'broadband', 'tv', 'phone', 'airtime'],
  charge: ['charge', 'charges'],
  refund: ['refund', 'refunds'],
};

const normalizeFilterValue = (value) =>
  (value || 'all').toString().toLowerCase().trim().replace(/[-\s]+/g, '_');

const matchesServiceType = (transactionType, selectedType) => {
  const selected = normalizeFilterValue(selectedType);
  if (selected === 'all') { return true; }

  const normalizedType = normalizeFilterValue(transactionType);
  const acceptedValues = SERVICE_TYPE_ALIASES[selected] || [selected];
  return acceptedValues.map(normalizeFilterValue).includes(normalizedType);
};

const matchesStatus = (transactionStatus, selectedStatus) => {
  const selected = normalizeFilterValue(selectedStatus);
  if (selected === 'all') { return true; }
  return normalizeFilterValue(transactionStatus) === selected;
};

const ReportsRedesigned = () => {
  const { t } = useTranslation();
  const { error: showError } = useToast();
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [paymentType, setPaymentType] = useState('all');
  const [transactionStatus, setTransactionStatus] = useState('all');
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage] = useState(20); // 20 transactions per page
  const { effectiveTheme } = useTheme();
  const [activeFilters, setActiveFilters] = useState(null);
  const [showAnalyticsModal, setShowAnalyticsModal] = useState(false);
  const [timeFilter, setTimeFilter] = useState('90d');
  const [selectedTransaction, setSelectedTransaction] = useState(null);

  // Service type options matching the API's service_type values.
  const serviceTypeOptions = [
    { value: 'all', label: t('allTypes', { ns: 'reports', defaultValue: 'All Types' }) },
    { value: 'collection', label: t('collection', { ns: 'reports', defaultValue: 'Collections' }) },
    { value: 'disbursement', label: t('disbursements', { ns: 'reports', defaultValue: 'Disbursements' }) },
    { value: 'utility', label: t('utilities', { ns: 'reports', defaultValue: 'Utilities' }) },
    { value: 'charge', label: t('charges', { ns: 'reports', defaultValue: 'Charges' }) },
    { value: 'refund', label: t('refund', { ns: 'reports', defaultValue: 'Refunds' }) },
  ];

  // Transaction status options
  const statusOptions = [
    { value: 'all', label: t('allStatus', { ns: 'reports', defaultValue: 'All Status' }) },
    { value: 'success', label: t('success', { ns: 'reports', defaultValue: 'Success' }) },
    { value: 'pending', label: t('pending', { ns: 'reports', defaultValue: 'Pending' }) },
    { value: 'failed', label: t('failed', { ns: 'reports', defaultValue: 'Failed' }) },
  ];

  const getCSSVariable = (varName) => {
    return getComputedStyle(document.documentElement).getPropertyValue(varName).trim();
  };

  const themeColors = useMemo(() => {
    return {
      textColor: getCSSVariable('--text-primary'),
      mutedTextColor: getCSSVariable('--text-muted'),
      borderColor: getCSSVariable('--border-primary'),
      cardBg: getCSSVariable('--card'),
      accentColor: getCSSVariable('--accent'),
      accent: getCSSVariable('--accent'), // Added for FullAnalytics compatibility
      effectiveTheme // Added for FullAnalytics compatibility
    };
  }, [effectiveTheme]);


  const toDateInputValue = (date) => {
    const tzOffset = date.getTimezoneOffset() * 60000;
    return new Date(date.getTime() - tzOffset).toISOString().slice(0, 10);
  };

  const currencyFormatter = useMemo(
    () =>
      new Intl.NumberFormat('en-GH', {
        style: 'currency',
        currency: 'GHS',
        minimumFractionDigits: 2,
      }),
    []
  );

  const formatCurrency = useCallback(
    (value) => currencyFormatter.format(value || 0),
    [currencyFormatter]
  );

  const buildActiveFilters = useCallback((overrides = {}) => ({
    startDate,
    endDate,
    paymentType,
    transactionStatus,
    ...overrides,
  }), [startDate, endDate, paymentType, transactionStatus]);

  // Time filter presets
  const applyTimeFilter = useCallback((preset) => {
    const today = new Date();
    const start = new Date();

    switch (preset) {
      case '14d':
        start.setDate(today.getDate() - 14);
        break;
      case '30d':
        start.setDate(today.getDate() - 30);
        break;
      case '90d':
        start.setMonth(today.getMonth() - 3);
        break;
      case 'custom':
        // Don't auto-set dates for custom, let user choose
        setTimeFilter('custom');
        return;
      default:
        return;
    }

    const startStr = toDateInputValue(start);
    const endStr = toDateInputValue(today);
    setStartDate(startStr);
    setEndDate(endStr);
    setTimeFilter(preset);
    setActiveFilters(buildActiveFilters({ startDate: startStr, endDate: endStr }));
  }, [buildActiveFilters]);

  const handleCustomDateChange = useCallback(() => {
    if (startDate && endDate) {
      if (new Date(startDate) <= new Date(endDate)) {
        setActiveFilters(buildActiveFilters());
        setTimeFilter('custom');
      } else {
        showError(t('startDateBeforeEndDate', { ns: 'reports' }));
      }
    }
  }, [startDate, endDate, buildActiveFilters, showError, t]);

  // Initialize with 90-day (3-month) view
  useEffect(() => {
    applyTimeFilter('90d');
  }, []);

  // Fetch reports data
  const { data: reportData, isLoading, error: loadError } = useQuery({
    queryKey: queryKeys.reports.list(activeFilters),
    queryFn: async () => {
      const { startDate: fromDate, endDate: toDate, paymentType: payment, transactionStatus: status } = activeFilters || {};
      if (!fromDate || !toDate) {
        return { transactions: [], summary: { totalAmount: 0, averageTransaction: 0, transactionCount: 0 } };
      }

      // Map UI paymentType to the report_type param (snake_case)
      const report_type = payment && payment !== 'all' ? payment : undefined;

      const response = await reportService.getGeneralTransactions({
        start_date: fromDate,
        end_date: toDate,
        report_type,
      });

      return {
        responseData: response,
        selectedPaymentType: payment,
        selectedStatus: status,
      };
    },
    enabled: !!(activeFilters?.startDate && activeFilters?.endDate),
    staleTime: 1 * 60 * 1000,
    refetchOnWindowFocus: false,
    select: ({ responseData, selectedPaymentType, selectedStatus }) => {
      // New envelope: { code, data: { data: [...], summary: { totalAmount, totalTransactions }, pagination } }
      const payload = responseData?.data ?? responseData ?? {};
      const transactionsRaw = Array.isArray(payload.data)
        ? payload.data
        : Array.isArray(payload.transactions)
          ? payload.transactions
          : Array.isArray(payload)
            ? payload
            : [];

      let normalized = transactionsRaw.map((tx, index) => normalizeTransaction(tx, index)).filter(Boolean);

      normalized = normalized.filter((tx) =>
        matchesServiceType(tx.type, selectedPaymentType) && matchesStatus(tx.status, selectedStatus)
      );

      const isFiltered = (selectedPaymentType && selectedPaymentType !== 'all') || (selectedStatus && selectedStatus !== 'all');

      const apiSummary = payload?.summary || {};
      const summedTotal = normalized.reduce((sum, tx) => sum + tx.amount, 0);
      const filteredCount = normalized.length;

      const totalAmount = isFiltered
        ? summedTotal
        : (parseAmount(apiSummary.totalAmount) || summedTotal);

      const transactionCount = isFiltered
        ? filteredCount
        : parseInteger(
          apiSummary.totalTransactions ?? payload?.pagination?.total,
          normalized.length
        );

      const averageTransaction = transactionCount > 0 ? totalAmount / transactionCount : 0;

      return {
        transactions: normalized,
        summary: { totalAmount, averageTransaction, transactionCount },
      };
    },
  });

  const transactions = reportData?.transactions || [];
  const summary = reportData?.summary || { totalAmount: 0, averageTransaction: 0, transactionCount: 0 };

  const sortedTransactions = useMemo(() => {
    return [...transactions].sort((a, b) => {
      const dateA = a.date ? Date.parse(a.date) : 0;
      const dateB = b.date ? Date.parse(b.date) : 0;
      return dateB - dateA;
    });
  }, [transactions]);

  // Pagination
  const totalItems = sortedTransactions.length;
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentTransactions = sortedTransactions.slice(startIndex, endIndex);

  useEffect(() => {
    if (activeFilters) { setCurrentPage(1); }
  }, [activeFilters]);

  const handlePageChange = (page) => setCurrentPage(page);

  // Export filtered transactions to Excel using xlsx
  const handleExportToExcel = () => {
    if (sortedTransactions.length === 0) {
      showError(t('noDataToExport', { ns: 'reports', defaultValue: 'No data to export' }));
      return;
    }

    // Sort by Service Type if no specific type filter is applied
    let exportTransactions = [...sortedTransactions];
    if (!activeFilters?.paymentType || activeFilters.paymentType === 'all') {
      exportTransactions.sort((a, b) => {
        const typeA = (a.type || '').toLowerCase();
        const typeB = (b.type || '').toLowerCase();
        return typeA.localeCompare(typeB);
      });
    }

    // Prepare data for Excel
    const excelData = exportTransactions.map((tx) => {
      const date = tx.date
        ? new Date(tx.date).toLocaleDateString('en-GB', {
          day: '2-digit',
          month: '2-digit',
          year: 'numeric',
          hour: '2-digit',
          minute: '2-digit'
        })
        : tx.displayDate || '';

      const amount = tx.amount ? parseFloat(tx.amount).toFixed(2) : '0.00';

      // Resolve customer name and phone per service type
      const exportCustomerName = tx.customerName && tx.customerName !== '—' ? tx.customerName : '';
      const exportCustomerPhone = tx.customerPhone && tx.customerPhone !== '—' ? tx.customerPhone : '';

      const row = {
        'Reference': tx.reference || '',
        'Customer Name': exportCustomerName,
        'Customer Phone': exportCustomerPhone,
        'Service Type': formatLabel(tx.type),
        'Transaction Type': tx.transactionType || '',
        'Collection Type': tx.collectionType && tx.collectionType !== '—' ? formatLabel(tx.collectionType) : '',
        'Channel': tx.channel && tx.channel !== '—' ? formatLabel(tx.channel) : '',
        'Narration': tx.narration && tx.narration !== '—' ? tx.narration : '',
        'Status': formatLabel(tx.status),
        'Reason': tx.reason || '',
        'Balance Before (GHS)': tx.balanceBefore || '',
        'Balance After (GHS)': tx.balanceAfter || '',
        'Settlement Status': tx.settlementStatus || '',
        'Amount (GHS)': Number(amount),
        'Date': date
      };

      return row;
    });

    const worksheet = XLSX.utils.json_to_sheet(excelData);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Transactions');

    // Adjust column widths automatically
    const wscols = [
      { wch: 36 }, // Reference
      { wch: 25 }, // Customer
      { wch: 18 }, // Phone
      { wch: 18 }, // Service Type
      { wch: 18 }, // Transaction Type
      { wch: 18 }, // Collection Type
      { wch: 15 }, // Channel
      { wch: 30 }, // Narration
      { wch: 12 }, // Status
      { wch: 28 }, // Reason
      { wch: 18 }, // Balance Before
      { wch: 18 }, // Balance After
      { wch: 18 }, // Settlement Status
      { wch: 15 }, // Amount (GHS)
      { wch: 20 }, // Date
    ];
    worksheet['!cols'] = wscols;

    const filename = `transaction_report_${new Date().toISOString().split('T')[0]}.xlsx`;
    XLSX.writeFile(workbook, filename);
  };


  // Quick insights calculation
  const quickInsights = useMemo(() => {
    if (sortedTransactions.length === 0) { return null; }

    const totalVolume = summary.totalAmount;
    const transactionCount = summary.transactionCount;
    const avgTransaction = summary.averageTransaction;

    // Calculate top payment type
    const typeTotals = sortedTransactions.reduce((acc, tx) => {
      const type = tx.type || 'unknown';
      acc[type] = (acc[type] || 0) + tx.amount;
      return acc;
    }, {});
    const topType = Object.entries(typeTotals).sort((a, b) => b[1] - a[1])[0];

    // Debug logging for topType
    logger.debug('Type Totals:', typeTotals);
    logger.debug('Top Type:', topType);

    // Calculate trend (last 3 days vs previous 3 days)
    const sortedByDate = [...sortedTransactions].sort((a, b) =>
      new Date(a.date) - new Date(b.date)
    );
    const recentTransactions = sortedByDate.slice(-3);
    const previousTransactions = sortedByDate.slice(-6, -3);
    const recentVolume = recentTransactions.reduce((sum, tx) => sum + tx.amount, 0);
    const previousVolume = previousTransactions.reduce((sum, tx) => sum + tx.amount, 0);
    const trend = previousVolume > 0 ? ((recentVolume - previousVolume) / previousVolume * 100).toFixed(1) : 0;

    return {
      totalVolume,
      transactionCount,
      avgTransaction,
      topType: topType ? { name: formatLabel(topType[0]), amount: topType[1] } : null,
      trend: parseFloat(trend)
    };
  }, [sortedTransactions, summary]);

  return (
    <div className="reports-redesigned">
      {/* Header Section */}
      <div className="reports-header">
        <div className="reports-header-top">
          <div className="reports-header-content">
            <h1>{t('reports', { ns: 'reports', defaultValue: 'Reports' })}</h1>
            <p>{t('reportsDescription', { ns: 'reports', defaultValue: 'Track your transaction performance and insights' })}</p>
          </div>

          <div style={{ display: 'flex', gap: '8px' }}>
            {/* Export Button */}
            <button
              className="analytics-export-btn"
              onClick={handleExportToExcel}
              disabled={isLoading || sortedTransactions.length === 0}
              title={t('exportToExcel', { ns: 'reports', defaultValue: 'Export to Excel' })}
            >
              <span className="material-symbols-outlined">download</span>
              {t('export', { ns: 'reports', defaultValue: 'Export' })}
            </button>

            {/* Analytics Toggle Button */}
            <button
              className="analytics-toggle-btn"
              onClick={() => setShowAnalyticsModal(true)}
              data-tour="reports-analytics-btn"
            >
              <span className="material-symbols-outlined">analytics</span>
              {t('viewAnalytics', { ns: 'reports', defaultValue: 'View Analytics' })}
            </button>
          </div>
        </div>

        {/* Filters Section */}
        <div className="reports-filters" data-tour="reports-filters">
          <div className="filter-group">
            <label>{t('timeRange', { ns: 'reports', defaultValue: 'Time Range' })}</label>
            <div className="time-filters">
              {[
                { key: '14d', label: t('last14Days', { ns: 'reports', defaultValue: '2 Weeks' }) },
                { key: '30d', label: t('last30Days', { ns: 'reports', defaultValue: '30 Days' }) },
                { key: '90d', label: t('last90Days', { ns: 'reports', defaultValue: '90 Days' }) },
                { key: 'custom', label: t('custom', { ns: 'reports', defaultValue: 'Custom' }) },
              ].map(filter => (
                <button
                  key={filter.key}
                  className={`time-filter-btn ${timeFilter === filter.key ? 'active' : ''}`}
                  onClick={() => applyTimeFilter(filter.key)}
                >
                  {filter.label}
                </button>
              ))}
            </div>
          </div>

          {/* Custom Date Range */}
          {timeFilter === 'custom' && (
            <div className="custom-date-range">
              <div className="date-inputs">
                <div>
                  <label>{t('startDate', { ns: 'reports' })}</label>
                  <input
                    type="date"
                    value={startDate}
                    onChange={(e) => setStartDate(e.target.value)}
                    className="date-input"
                  />
                </div>
                <div>
                  <label>{t('endDate', { ns: 'reports' })}</label>
                  <input
                    type="date"
                    value={endDate}
                    onChange={(e) => setEndDate(e.target.value)}
                    className="date-input"
                  />
                </div>
                <button
                  className="apply-dates-btn"
                  onClick={handleCustomDateChange}
                  disabled={!startDate || !endDate}
                >
                  {t('apply', { ns: 'reports', defaultValue: 'Apply' })}
                </button>
              </div>
            </div>
          )}

          {/* Transaction Type and Status Filters - Side by Side */}
          <div className="filter-row">
            <div className="filter-group">
              <label>{t('transactionType', { ns: 'reports', defaultValue: 'Transaction Type' })}</label>
              <CustomSelect
                name="paymentType"
                value={paymentType}
                onChange={(e) => {
                  const val = e.target.value;
                  setPaymentType(val);
                  setActiveFilters(prev => ({
                    ...prev,
                    startDate,
                    endDate,
                    paymentType: val
                  }));
                }}
                options={serviceTypeOptions}
              />
            </div>

            <div className="filter-group">
              <label>{t('transactionStatus', { ns: 'reports', defaultValue: 'Transaction Status' })}</label>
              <CustomSelect
                name="transactionStatus"
                value={transactionStatus}
                onChange={(e) => {
                  const val = e.target.value;
                  setTransactionStatus(val);
                  setActiveFilters(prev => ({
                    ...prev,
                    startDate,
                    endDate,
                    transactionStatus: val
                  }));
                }}
                options={statusOptions}
              />
            </div>
          </div>
        </div>
      </div> {/* Close reports-header */}

      {/* Date range context note — subtle hint that analytics reflects the selected period */}
      {activeFilters?.startDate && activeFilters?.endDate && !isLoading && (
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: '6px',
          padding: '6px 12px',
          marginBottom: '8px',
          borderRadius: '6px',
          background: 'var(--bg-tertiary)',
          border: '1px solid var(--border-primary)',
          width: 'fit-content',
          fontSize: '0.78rem',
          color: 'var(--text-muted)',
          lineHeight: 1.4,
        }}>
          <span className="material-symbols-outlined" style={{ fontSize: '14px', flexShrink: 0 }}>
            info
          </span>
          Analytics based on transactions from{' '}
          <strong style={{ color: 'var(--text-secondary)', fontWeight: 600 }}>
            {new Date(activeFilters.startDate).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })}
          </strong>
          {' '}to{' '}
          <strong style={{ color: 'var(--text-secondary)', fontWeight: 600 }}>
            {new Date(activeFilters.endDate).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })}
          </strong>
          {paymentType !== 'all' && (
            <span style={{ marginLeft: '4px' }}>
              · {serviceTypeOptions.find(o => o.value === paymentType)?.label || paymentType}
            </span>
          )}
        </div>
      )}

      {/* Stats Cards - Using Dashboard MetricCard Component */}
      <div className="metrics">
        <MetricCard
          title={t('totalVolume', { ns: 'reports', defaultValue: 'Total Volume' })}
          value={formatCurrency(quickInsights?.totalVolume || 0)}
          icon="account_balance_wallet"
          accent="var(--accent)"
          accentSoft="rgba(37, 99, 235, 0.12)"
          accentStrong="rgba(37, 99, 235, 0.28)"
        />

        <MetricCard
          title={t('transactions', { ns: 'reports', defaultValue: 'Transactions' })}
          value={quickInsights?.transactionCount || 0}
          hint={formatCurrency(quickInsights?.avgTransaction || 0) + ' avg'}
          icon="receipt_long"
          accent="var(--success)"
          accentSoft="rgba(16, 185, 129, 0.12)"
          accentStrong="rgba(16, 185, 129, 0.28)"
        />

        {/* Top Transaction Type Card - Shows highest revenue source */}
        <MetricCard
          title={t('topTransactionType', { ns: 'reports', defaultValue: 'Top Transaction Type' })}
          value={formatCurrency(quickInsights?.topType?.amount || 0)}
          hint={quickInsights?.topType?.name ||
            (quickInsights?.topType?.amount ? 'Transaction Type' : 'No Data')}
          icon="leaderboard"
          accent="var(--primary)"
          accentSoft="rgba(37, 99, 235, 0.12)"
          accentStrong="rgba(37, 99, 235, 0.28)"
        />
      </div>

      <div className="transactions-table">
        {isLoading ? (
          <div className="loading-state">
            <div className="loading-spinner"></div>
            <p>{t('loading', { ns: 'common', defaultValue: 'Loading...' })}</p>
          </div>
        ) : currentTransactions.length === 0 ? (
          <div className="empty-state">
            <span className="material-symbols-outlined">receipt_long</span>
            <p>{t('noTransactions', { ns: 'reports', defaultValue: 'No transactions found' })}</p>
          </div>
        ) : (
          <>
            <div className="table-header" style={{ gridTemplateColumns: '2fr 1.5fr 1.5fr 1.2fr 1.2fr' }}>
              <div>{t('reference', { ns: 'reports', defaultValue: 'Reference' })}</div>
              <div>{t('customer', { ns: 'common', defaultValue: 'Customer' })}</div>
              <div>{t('type', { ns: 'reports', defaultValue: 'Type' })}</div>
              <div>{t('amount', { ns: 'reports', defaultValue: 'Amount' })}</div>
              <div>{t('status', { ns: 'reports', defaultValue: 'Status' })}</div>
            </div>
            <div className="table-body" key={`page-${currentPage}`}>
              {currentTransactions.map((transaction, index) => (
                <div
                  key={transaction.id || `${transaction.reference}-${index}`}
                  className="table-row"
                  onClick={() => setSelectedTransaction(transaction)}
                  style={{ cursor: 'pointer', gridTemplateColumns: '2fr 1.5fr 1.5fr 1.2fr 1.2fr' }}
                >
                  {/* Reference + narration */}
                  <div>
                    <div>{transaction.reference}</div>
                    {transaction.narration && transaction.narration !== '—' && (
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '2px' }}>
                        {transaction.narration}
                      </div>
                    )}
                  </div>

                  {/* Customer name + phone */}
                  <div>
                    {transaction.customerName && transaction.customerName !== '—' ? (
                      <div style={{ fontWeight: 500, fontSize: '0.85rem', color: 'var(--text-primary)' }}>
                        {transaction.customerName}
                      </div>
                    ) : (
                      <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>—</div>
                    )}
                    {transaction.customerPhone && transaction.customerPhone !== '—' && (
                      <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginTop: '2px' }}>
                        {transaction.customerPhone}
                      </div>
                    )}
                  </div>

                  {/* Type badge + sub-details */}
                  <div>
                    <span className="chip" style={getTypeBadgeStyles(transaction.type)}>
                      {formatLabel(transaction.type)}
                    </span>
                    {transaction.transactionType && (
                      <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '4px' }}>
                        {transaction.transactionType}
                      </div>
                    )}
                    {transaction.collectionType && transaction.collectionType !== '—' && (
                      <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '2px' }}>
                        {formatLabel(transaction.collectionType)}
                      </div>
                    )}
                  </div>

                  {/* Amount + channel */}
                  <div>
                    {formatCurrency(transaction.amount)}
                    {transaction.channel && transaction.channel !== '—' && (
                      <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '2px' }}>
                        {formatLabel(transaction.channel)}
                      </div>
                    )}
                  </div>

                  {/* Status + reason */}
                  <div>
                    <span className="chip" style={getStatusBadgeStyles(transaction.status)}>
                      {formatLabel(transaction.status)}
                    </span>
                    {transaction.reason && (
                      <div style={{
                        fontSize: '0.72rem',
                        color: 'var(--text-muted)',
                        marginTop: '3px',
                        maxWidth: '120px',
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                        textTransform: 'capitalize',
                      }}
                        title={transaction.reason}
                      >
                        {transaction.reason}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </>
        )}
      </div>

      {
        totalItems > 0 && (
          <Pagination
            currentPage={currentPage}
            totalItems={totalItems}
            itemsPerPage={itemsPerPage}
            onPageChange={handlePageChange}
            showInfo={true}
          />
        )
      }

      {/* Transaction Detail Modal */}
      {selectedTransaction && (
        <div
          onClick={() => setSelectedTransaction(null)}
          style={{
            position: 'fixed', inset: 0,
            backgroundColor: 'rgba(0,0,0,0.5)',
            backdropFilter: 'blur(4px)',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            zIndex: 99999, padding: '16px',
          }}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              backgroundColor: 'var(--card)',
              borderRadius: '16px',
              width: '100%', maxWidth: '480px',
              maxHeight: '88vh', overflowY: 'auto',
              boxShadow: 'var(--shadow-xl)',
            }}
          >
            {/* Header */}
            <div style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start',
              padding: '18px 20px 14px',
              borderBottom: '1px solid var(--border-primary)',
              position: 'sticky', top: 0, background: 'var(--card)', zIndex: 1,
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <span className="material-symbols-outlined" style={{ fontSize: 22, color: 'var(--accent)' }}>receipt_long</span>
                <div>
                  <div style={{ fontWeight: 700, color: 'var(--text-primary)', fontSize: '1rem' }}>Transaction Details</div>
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.75rem', fontFamily: 'monospace', marginTop: 2 }}>
                    {selectedTransaction.reference}
                  </div>
                </div>
              </div>
              <button type="button" onClick={() => setSelectedTransaction(null)}
                style={{ border: 'none', background: 'none', cursor: 'pointer', color: 'var(--text-muted)', padding: 4, display: 'flex', alignItems: 'center' }}>
                <span className="material-symbols-outlined" style={{ fontSize: 22 }}>close</span>
              </button>
            </div>

            {/* Amount hero */}
            <div style={{
              textAlign: 'center', padding: '20px 20px 16px',
              background: selectedTransaction.status === 'success' ? 'var(--success-bg)'
                : selectedTransaction.status === 'failed' ? 'var(--error-bg)'
                : 'var(--warning-bg)',
              borderBottom: '1px solid var(--border-primary)',
            }}>
              <div style={{
                fontSize: '2rem', fontWeight: '800',
                color: selectedTransaction.status === 'success' ? 'var(--success)'
                  : selectedTransaction.status === 'failed' ? 'var(--error)'
                  : 'var(--warning)',
              }}>
                {formatCurrency(selectedTransaction.amount)}
              </div>
              <div style={{ marginTop: 8 }}>
                <span className="chip" style={getStatusBadgeStyles(selectedTransaction.status)}>
                  {formatLabel(selectedTransaction.status)}
                </span>
              </div>
              {selectedTransaction.narration && selectedTransaction.narration !== '—' && (
                <div style={{ marginTop: 8, fontSize: '0.85rem', color: 'var(--text-muted)' }}>
                  {selectedTransaction.narration}
                </div>
              )}
              {selectedTransaction.reason && (
                <div style={{ marginTop: 6, fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'capitalize' }}>
                  {selectedTransaction.reason}
                </div>
              )}
            </div>

            {/* Detail rows */}
            <div style={{ padding: '4px 20px 20px' }}>
              {[
                { label: 'Customer', value: selectedTransaction.customerName && selectedTransaction.customerName !== '—' ? selectedTransaction.customerName : null },
                { label: 'Phone', value: selectedTransaction.customerPhone && selectedTransaction.customerPhone !== '—' ? selectedTransaction.customerPhone : null },
                { label: 'Type', value: formatLabel(selectedTransaction.type) },
                { label: 'Transaction Type', value: selectedTransaction.transactionType },
                { label: 'Collection Type', value: selectedTransaction.collectionType !== '—' ? formatLabel(selectedTransaction.collectionType) : null },
                { label: 'Channel', value: selectedTransaction.channel !== '—' ? formatLabel(selectedTransaction.channel) : null },
                { label: 'Balance Before', value: selectedTransaction.balanceBefore ? `GHS ${selectedTransaction.balanceBefore}` : null },
                { label: 'Balance After', value: selectedTransaction.balanceAfter ? `GHS ${selectedTransaction.balanceAfter}` : null },
                { label: 'Settlement', value: selectedTransaction.settlementStatus },
                { label: 'Date', value: selectedTransaction.displayDate },
              ].filter(row => row.value).map(row => (
                <div key={row.label} style={{
                  display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start',
                  padding: '11px 0', borderBottom: '1px solid var(--border-primary)', gap: '16px',
                }}>
                  <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)', flexShrink: 0, minWidth: '110px' }}>
                    {row.label}
                  </span>
                  <span style={{
                    fontSize: '0.875rem', fontWeight: '500', color: 'var(--text-primary)',
                    textAlign: 'right', wordBreak: 'break-word',
                  }}>
                    {row.value}
                  </span>
                </div>
              ))}
            </div>

            <div style={{ padding: '0 20px 20px' }}>
              <button type="button" onClick={() => setSelectedTransaction(null)}
                style={{
                  width: '100%', padding: '12px', borderRadius: '10px',
                  border: 'none', background: 'var(--accent)', color: 'var(--text-inverse)',
                  fontWeight: '600', fontSize: '0.9rem', cursor: 'pointer',
                }}>
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Analytics Modal */}
      {showAnalyticsModal && createPortal(
        <div
          style={{
            position: 'fixed',
            inset: 0,
            backgroundColor: 'rgba(0,0,0,0.8)',
            backdropFilter: 'blur(12px)',
            WebkitBackdropFilter: 'blur(12px)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 999999,
            padding: '20px'
          }}
          onClick={() => setShowAnalyticsModal(false)}
        >
          <div
            style={{
              backgroundColor: 'var(--card)',
              borderRadius: '16px',
              maxWidth: '1200px',
              width: '100%',
              maxHeight: '90vh',
              overflow: 'auto',
              position: 'relative',
              boxShadow: '0 25px 50px rgba(0, 0, 0, 0.25)',
              transform: 'scale(1)',
              animation: 'modalSlideIn 0.3s ease-out'
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div style={{ padding: '32px' }}>
              <FullAnalytics
                transactions={sortedTransactions}
                summary={summary}
                timeFilter={timeFilter}
                selectedPaymentType={paymentType}
                themeColors={themeColors}
                formatCurrency={formatCurrency}
              />
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
};

export default ReportsRedesigned;
