/**
 * Full Analytics Component
 * 
 * Comprehensive analytics with charts, insights, and advanced filtering.
 * Designed to be powerful yet user-friendly with progressive disclosure.
 */

import React, { useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Line, Bar, Pie, Doughnut } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

const FullAnalytics = ({ transactions, summary, timeFilter, themeColors, formatCurrency, selectedPaymentType }) => {
  const { t } = useTranslation();
  const [activeChart, setActiveChart] = useState('volume'); // volume, distribution, patterns, insights

  // Calculate analytics data
  const analyticsData = useMemo(() => {
    if (!transactions || transactions.length === 0) {
      return {
        volumeData: { labels: [], datasets: [] },
        distributionData: { labels: [], datasets: [] },
        patternsData: { labels: [], datasets: [] },
        insights: []
      };
    }

    // Volume over time data
    const volumeByDate = transactions.reduce((acc, tx) => {
      if (!tx.date) {return acc;}
      const date = tx.date.split('T')[0];
      acc[date] = (acc[date] || 0) + tx.amount;
      return acc;
    }, {});

    const sortedDates = Object.keys(volumeByDate).sort();
    const volumeData = {
      labels: sortedDates.map(date => {
        const d = new Date(date);
        return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
      }),
      datasets: [{
        data: sortedDates.map(date => volumeByDate[date]),
        borderColor: themeColors.accentColor,
        backgroundColor: themeColors.effectiveTheme === 'dark' 
          ? 'rgba(59, 130, 246, 0.15)' 
          : 'rgba(59, 130, 246, 0.1)',
        fill: true,
        tension: 0.4,
        borderWidth: 2,
        pointRadius: 4,
        pointHoverRadius: 6,
      }]
    };

    // Payment type distribution
    const typeTotals = transactions.reduce((acc, tx) => {
      const type = tx.type || 'unknown';
      acc[type] = (acc[type] || 0) + tx.amount;
      return acc;
    }, {});

    const distributionData = {
      labels: Object.keys(typeTotals).map(type => 
        t(type, { ns: 'reports', defaultValue: type.charAt(0).toUpperCase() + type.slice(1) })
      ),
      datasets: [{
        data: Object.values(typeTotals),
        backgroundColor: [
          '#3b82f6', // blue
          '#10b981', // green
          '#f59e0b', // amber
          '#8b5cf6', // purple
          '#ef4444', // red
          '#6b7280', // gray
        ],
        borderWidth: 0,
        borderRadius: 4,
      }]
    };

    // Transaction patterns data - hourly activity analysis
    const hourlyActivity = transactions.reduce((acc, tx) => {
      if (!tx.date) {return acc;}
      const hour = new Date(tx.date).getHours();
      const hourLabel = `${hour}:00`;
      acc[hourLabel] = (acc[hourLabel] || 0) + 1;
      return acc;
    }, {});

    const sortedHours = Array.from({ length: 24 }, (_, i) => `${i}:00`);
    const patternsData = {
      labels: sortedHours,
      datasets: [{
        label: t('transactionActivity', { ns: 'reports', defaultValue: 'Transaction Activity' }),
        data: sortedHours.map(hour => hourlyActivity[hour] || 0),
        borderColor: themeColors?.accent || '#3b82f6',
        backgroundColor: (themeColors?.accent || '#3b82f6') + '20',
        borderWidth: 2,
        fill: true,
        tension: 0.4,
        pointBackgroundColor: themeColors?.accent || '#3b82f6',
        pointBorderColor: '#fff',
        pointBorderWidth: 2,
        pointRadius: 4,
        pointHoverRadius: 6,
      }]
    };

    // Generate insights
    const insights = [];
    
    // Top payment type insight
    const topType = Object.entries(typeTotals).sort((a, b) => b[1] - a[1])[0];
    if (topType) {
      const percentage = ((topType[1] / Object.values(typeTotals).reduce((a, b) => a + b, 0)) * 100).toFixed(1);
      insights.push({
        type: 'success',
        icon: 'payments',
        title: t('topPaymentType', { ns: 'reports', defaultValue: 'Top Payment Type' }),
        description: t('topPaymentTypeDesc', { 
          ns: 'reports', 
          defaultValue: '{{type}} accounts for {{percentage}}% of total volume',
          type: t(topType[0], { ns: 'reports', defaultValue: topType[0].charAt(0).toUpperCase() + topType[0].slice(1) }),
          percentage
        })
      });
    }

    // Average transaction insight
    const avgTransaction = summary.averageTransaction || 0;
    if (avgTransaction > 1000) {
      insights.push({
        type: 'success',
        icon: 'account_balance_wallet',
        title: t('highValueTransactions', { ns: 'reports', defaultValue: 'High Value Transactions' }),
        description: t('avgTransactionHigh', { 
          ns: 'reports', 
          defaultValue: 'Average transaction of {{amount}} indicates high-value customers',
          amount: formatCurrency(avgTransaction)
        })
      });
    } else if (avgTransaction > 0 && avgTransaction <= 100) {
      insights.push({
        type: 'info',
        icon: 'payments',
        title: t('frequentSmallTransactions', { ns: 'reports', defaultValue: 'Frequent Small Transactions' }),
        description: t('avgTransactionLow', { 
          ns: 'reports', 
          defaultValue: 'Average transaction of {{amount}} suggests frequent micro-transactions',
          amount: formatCurrency(avgTransaction)
        })
      });
    }

    // Failed transactions analysis
    const failedTransactions = transactions.filter(tx => 
      tx.status === 'failed' || tx.status === 'error'
    ).length;
    
    if (failedTransactions > 0) {
      const failedPercentage = (failedTransactions / transactions.length * 100).toFixed(1);
      insights.push({
        type: 'warning',
        icon: 'error',
        title: t('failedTransactionsFound', { ns: 'reports', defaultValue: 'Failed Transactions Detected' }),
        description: t('failedTransactionsDesc', { 
          ns: 'reports', 
          defaultValue: '{{count}} failed transactions ({{percentage}}%) - review payment processing',
          count: failedTransactions,
          percentage: failedPercentage
        })
      });
    }

    // Transaction frequency insight
    if (transactions.length > 0) {
      const dates = transactions.map(tx => tx.date ? tx.date.split('T')[0] : null).filter(Boolean);
      const uniqueDays = new Set(dates).size;
      
      if (uniqueDays > 1) {
        const avgPerDay = (transactions.length / uniqueDays).toFixed(1);
        insights.push({
          type: 'warning',
          icon: 'calendar_today',
          title: t('transactionFrequency', { ns: 'reports', defaultValue: 'Transaction Frequency' }),
          description: t('transactionFrequencyDesc', { 
            ns: 'reports', 
            defaultValue: 'Averaging {{count}} transactions per day over {{days}} days',
            count: avgPerDay,
            days: uniqueDays
          })
        });
      }
    }

    // Peak transaction time analysis
    const hourCounts = transactions.reduce((acc, tx) => {
      if (tx.date) {
        const hour = new Date(tx.date).getHours();
        acc[hour] = (acc[hour] || 0) + 1;
      }
      return acc;
    }, {});
    
    const peakHour = Object.entries(hourCounts).sort((a, b) => b[1] - a[1])[0];
    if (peakHour && peakHour[1] > 1) {
      insights.push({
        type: 'error',
        icon: 'schedule',
        title: t('peakTransactionTime', { ns: 'reports', defaultValue: 'Peak Activity Time' }),
        description: t('peakTransactionTimeDesc', { 
          ns: 'reports', 
          defaultValue: 'Most transactions occur around {{hour}}:00 ({{count}} transactions)',
          hour: peakHour[0],
          count: peakHour[1]
        })
      });
    }

    return {
      volumeData,
      distributionData,
      patternsData,
      insights
    };
  }, [transactions, summary, themeColors, formatCurrency, t]);

  const chartOptions = useMemo(() => ({
    responsive: true,
    maintainAspectRatio: false,
    interaction: {
      intersect: false,
      mode: 'index',
    },
    plugins: {
      legend: {
        display: false, // Hide legend completely
      },
      tooltip: {
        backgroundColor: themeColors.cardBg,
        titleColor: themeColors.textColor,
        bodyColor: themeColors.textColor,
        borderColor: themeColors.borderColor,
        borderWidth: 1,
        padding: 12,
        cornerRadius: 8,
        callbacks: {
          label: function(context) {
            const value = context.parsed.y || context.parsed;
            return `Amount: ${formatCurrency(value)}`;
          }
        }
      }
    },
    scales: {
      x: {
        grid: { display: false },
        ticks: { color: themeColors.textColor }
      },
      y: {
        beginAtZero: true,
        grid: { color: themeColors.borderColor },
        ticks: { 
          color: themeColors.textColor,
          callback: function(value) {
            if (value >= 1000000) {return (value / 1000000).toFixed(1) + 'M';}
            if (value >= 1000) {return (value / 1000).toFixed(1) + 'K';}
            return value;
          }
        }
      }
    }
  }), [themeColors, formatCurrency]);

  const pieChartOptions = useMemo(() => ({
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        display: false, // Hide legend completely
      },
      tooltip: {
        backgroundColor: themeColors.cardBg,
        titleColor: themeColors.textColor,
        bodyColor: themeColors.textColor,
        borderColor: themeColors.borderColor,
        borderWidth: 1,
        padding: 12,
        cornerRadius: 8,
        callbacks: {
          label: function(context) {
            const label = context.label || '';
            const value = context.parsed;
            const total = context.dataset.data.reduce((a, b) => a + b, 0);
            const percentage = ((value / total) * 100).toFixed(1);
            return `${label}: ${formatCurrency(value)} (${percentage}%)`;
          }
        }
      }
    }
  }), [themeColors, formatCurrency]);

  const chartTabs = [
    { key: 'volume', label: t('volumeTrends', { ns: 'reports', defaultValue: 'Volume Trends' }), icon: 'trending_up' },
    { key: 'distribution', label: t('distribution', { ns: 'reports', defaultValue: 'Distribution' }), icon: 'pie_chart' },
    { key: 'patterns', label: t('transactionPatterns', { ns: 'reports', defaultValue: 'Transaction Patterns' }), icon: 'schedule' },
  ];

  return (
    <div className="full-analytics-content">
      {/* Analytics Insights */}
      <div className="analytics-insights">
        <div className="insights-grid">
          {analyticsData.insights.map((insight, index) => (
            <div key={index} className={`insight-card insight-${insight.type}`}>
              <div className="insight-icon">
                <span className="material-symbols-outlined">{insight.icon}</span>
              </div>
              <div className="insight-content">
                <div className="insight-title">{insight.title}</div>
                <p>{insight.description}</p>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Chart Tabs */}
      <div className="chart-tabs">
        <div className="tab-buttons">
          {chartTabs.map(tab => (
            <button
              key={tab.key}
              className={`tab-btn ${activeChart === tab.key ? 'active' : ''}`}
              onClick={() => setActiveChart(tab.key)}
            >
              <span className="material-symbols-outlined">{tab.icon}</span>
              {tab.label}
            </button>
          ))}
        </div>

        <div className="chart-container">
          {activeChart === 'volume' && (
            <div className="chart-wrapper">
              <div style={{ height: '300px' }}>
                <Line data={analyticsData.volumeData} options={chartOptions} />
              </div>
            </div>
          )}

          {activeChart === 'distribution' && (
            <div className="chart-wrapper">
              <div style={{ height: '300px' }}>
                <Doughnut data={analyticsData.distributionData} options={pieChartOptions} />
              </div>
            </div>
          )}

          {activeChart === 'patterns' && (
            <div className="chart-wrapper">
              <h4>{t('hourlyTransactionActivity', { ns: 'reports', defaultValue: 'Hourly Transaction Activity' })}</h4>
              <div style={{ height: '300px' }}>
                <Line data={analyticsData.patternsData} options={chartOptions} />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Detailed Metrics */}
      <div className="detailed-metrics">
        <div className="metrics-grid">
          <div className="metric-item">
            <div className="metric-label">{t('totalVolume', { ns: 'reports', defaultValue: 'Total Volume' })}</div>
            <div className="metric-value">{formatCurrency(summary.totalAmount || 0)}</div>
          </div>
          <div className="metric-item">
            <div className="metric-label">{t('totalTransactions', { ns: 'reports', defaultValue: 'Total Transactions' })}</div>
            <div className="metric-value">{summary.transactionCount || 0}</div>
          </div>
          <div className="metric-item">
            <div className="metric-label">{t('averageTransaction', { ns: 'reports', defaultValue: 'Average Transaction' })}</div>
            <div className="metric-value">{formatCurrency(summary.averageTransaction || 0)}</div>
          </div>
          </div>
      </div>
    </div>
  );
};

export default FullAnalytics;
