/**
 * Reports Service
 *
 * Typed consumer report helpers for the new /auth/get-* endpoints.
 * All params are snake_case per API convention.
 * Response envelope: { code, data: { data: [...], summary: { totalAmount, totalTransactions }, pagination: { page, limit, total, totalPages, hasMore } } }
 */

import apiRequest from '@/shared/services/apiClient.js';

const buildQuery = (params = {}) => {
  const searchParams = new URLSearchParams();
  Object.entries(params).forEach(([key, value]) => {
    if (value !== undefined && value !== null && value !== '') {
      searchParams.append(key, value);
    }
  });
  const q = searchParams.toString();
  return q ? `?${q}` : '';
};

const reportService = {
  /**
   * General / cross-cutting ledger view.
   * Use for the Reports page and any "all activity" dashboard.
   * @param {Object} params
   * @param {string} [params.start_date] - YYYY-MM-DD
   * @param {string} [params.end_date]   - YYYY-MM-DD
   * @param {number} [params.page]       - 1-based, default 1
   * @param {string} [params.report_type] - disbursements | collections | settlements | utilities | refund
   * @param {string} [params.status]
   * @param {string} [params.channel]
   * @param {string} [params.transaction_type]
   * @param {string} [params.currency]
   * @returns {Promise<Object>} { data: { data: [...], summary, pagination } }
   */
  async getGeneralTransactions({ start_date, end_date, page = 1, ...filters } = {}) {
    return apiRequest(
      `/auth/get-general-transactions${buildQuery({ start_date, end_date, page, ...filters })}`,
      { method: 'GET' }
    );
  },

  /**
   * Outbound payments: deposit and wallet_transfer only.
   * @param {Object} params
   * @param {string} [params.start_date]
   * @param {string} [params.end_date]
   * @param {number} [params.page]
   * @param {string} [params.channel]     - BANK | MOBILE_MONEY | WALLET
   * @param {string} [params.status]      - FAILED | PENDING | PROCESSING | SUCCESS
   * @param {string} [params.disburse_type] - deposit | wallet_transfer
   * @param {string} [params.currency]
   * @returns {Promise<Object>} { data: { data: [...], summary, pagination } }
   */
  async getDisbursements({ start_date, end_date, page = 1, ...filters } = {}) {
    return apiRequest(
      `/auth/get-disbursements${buildQuery({ start_date, end_date, page, ...filters })}`,
      { method: 'GET' }
    );
  },

  /**
   * Inbound credits: MoMo, bank, and wallet-to-wallet.
   * @param {Object} params
   * @param {string} [params.start_date]
   * @param {string} [params.end_date]
   * @param {number} [params.page]
   * @param {string} [params.channel]  - BANK | momo | MOMO-MTN | MOMO-TELECEL | WALLET
   * @param {string} [params.status]   - defaults to successful only when omitted
   * @param {string} [params.currency]
   * @returns {Promise<Object>} { data: { data: [...], summary, pagination } }
   */
  async getCollections({ start_date, end_date, page = 1, ...filters } = {}) {
    return apiRequest(
      `/auth/get-collections${buildQuery({ start_date, end_date, page, ...filters })}`,
      { method: 'GET' }
    );
  },

  /**
   * Settlement payouts to the user's linked settlement account.
   * @param {Object} params
   * @param {string} [params.start_date]
   * @param {string} [params.end_date]
   * @param {number} [params.page]
   * @param {string} [params.channel]  - BANK | MOBILE_MONEY
   * @param {string} [params.status]   - FAILED | PROCESSING | SUCCESS
   * @param {string} [params.currency]
   * @returns {Promise<Object>} { data: { data: [...], summary, pagination } }
   */
  async getSettlements({ start_date, end_date, page = 1, ...filters } = {}) {
    return apiRequest(
      `/auth/get-settlements${buildQuery({ start_date, end_date, page, ...filters })}`,
      { method: 'GET' }
    );
  },

  /**
   * Bill pay / airtime / data / broadband purchases.
   * @param {Object} params
   * @param {string} [params.start_date]
   * @param {string} [params.end_date]
   * @param {number} [params.page]
   * @param {string} [params.status]       - FAILED | PENDING | SUCCESS
   * @param {string} [params.service_name] - e.g. "MTN Airtime", "Electricity", "DSTV"
   * @returns {Promise<Object>} { data: { data: [...], summary, pagination } }
   */
  async getUtilities({ start_date, end_date, page = 1, ...filters } = {}) {
    return apiRequest(
      `/auth/get-utilities${buildQuery({ start_date, end_date, page, ...filters })}`,
      { method: 'GET' }
    );
  },
};

export default reportService;
